var listeners={};function add(e,n,i){listeners[e="number"==typeof e?"(min-width: "+e+"px)":e]=listeners[e]||[],listeners[e].push({yes:n,no:i})}function watch(){for(var e in listeners)!function(n){var i=window.matchMedia(n);fire(n,i),i.onchange=function(e){fire(n,i)}}(e)}function fire(e,n){for(var i=n.matches?"yes":"no",t=0;t<listeners[e].length;t++)listeners[e][t][i]()}export{add,watch,fire};